mapper.select:
SELECT s.id, s.doctor_id, s.dept_id, s.work_date, s.work_time, s.total_number, s.schedule_status, s.create_time, s.update_time, d.doctor_name, d.title, d.avatar, dept.dept_name, ns.remain_number, ns.source_status FROM hos_schedule s LEFT JOIN hos_doctor d ON s.doctor_id = d.id LEFT JOIN hos_department dept ON s.dept_id = dept.id LEFT JOIN hos_number_source ns ON s.id = ns.schedule_id WHERE s.deleted = 0
AND s.dept_id = #{params.deptId}
AND s.doctor_id = #{params.doctorId}
AND d.doctor_name LIKE CONCAT('%', #{params.doctorName}, '%')
AND s.work_date >= #{params.startDate}
AND s.work_date <= #{params.endDate}
AND s.schedule_status = #{params.scheduleStatus}
ORDER BY s.work_date ASC, s.work_time ASC

SELECT COUNT(*) FROM hos_schedule
WHERE doctor_id = #{schedule.doctorId}
  AND work_date = #{schedule.workDate}
  AND work_time = #{schedule.workTime}
  AND deleted = 0

    AND id != #{schedule.id}
